request.query:
BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?activity ?activityName ?callBA ?callBAName WHERE {
  {
    ?activity rdf:type vocab:activity .
    ?activity vocab:NamedElement_name ?activityName .
    FILTER(CONTAINS(LCASE(STR(?activityName)), LCASE("aps")))
    OPTIONAL {
      ?activity vocab:Activity_node ?node .
      ?node vocab:NamedElement_name ?nodeName .
      FILTER(CONTAINS(LCASE(STR(?nodeName)), LCASE("aps")))
    }
  }
  UNION
  {
    ?callBA rdf:type vocab:call%20behavior%20action .
    ?callBA vocab:NamedElement_name ?callBAName .
    FILTER(CONTAINS(LCASE(STR(?callBAName)), LCASE("aps")))
  }
}
LIMIT 25
